files.patch:
@@ -0,0 +1,13 @@
+{
+  "name": "backspace_at_origin",
+  "description": "BS at column 0 stays at column 0",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "0841",
+  "comment": "BS from (0,0) stays at (0,0); print A at (0,0); cursor at (0,1)",
+  "expected": {
+    "cursor": { "row": 0, "col": 1 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "sgr_bg_indexed",
+  "description": "SGR 48;5;N sets 256-color indexed background; SGR 0 resets",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b34383b353b32316d411b5b306d42",
+  "comment": "SGR 48;5;21 (indexed bg 21) + print A; SGR 0 (reset) + print B; A has indexed bg, B has default",
+  "expected": {
+    "cursor": { "row": 0, "col": 2 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A", "attrs": { "bg_color": { "indexed": 21 } } },
+      { "row": 0, "col": 1, "char": "B" }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "sgr_combined_attrs",
+  "description": "Multiple SGR params in one sequence: bold + italic + named fg color",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b313b333b33316d411b5b306d42",
+  "comment": "SGR 1;3;31 (bold+italic+red fg) + print A; SGR 0 (reset) + print B; A has bold+italic+named(1) fg",
+  "expected": {
+    "cursor": { "row": 0, "col": 2 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A", "attrs": { "bold": true, "italic": true, "fg_color": { "named": 1 } } },
+      { "row": 0, "col": 1, "char": "B" }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "sgr_indexed_color",
+  "description": "SGR 38;5;N sets 256-color indexed foreground; SGR 0 resets",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b33383b353b3139366d411b5b306d42",
+  "comment": "SGR 38;5;196 (indexed fg 196) + print A; SGR 0 (reset) + print B; A has indexed fg, B has default",
+  "expected": {
+    "cursor": { "row": 0, "col": 2 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A", "attrs": { "fg_color": { "indexed": 196 } } },
+      { "row": 0, "col": 1, "char": "B" }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "sgr_named_fg_reset",
+  "description": "SGR 32 sets green fg; SGR 39 resets to default fg",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b33326d581b5b33396d59",
+  "comment": "SGR 32 (green fg = named 2) + print X; SGR 39 (default fg) + print Y; X has named(2) fg, Y has default",
+  "expected": {
+    "cursor": { "row": 0, "col": 2 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "X", "attrs": { "fg_color": { "named": 2 } } },
+      { "row": 0, "col": 1, "char": "Y" }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "sgr_rgb_color",
+  "description": "SGR 38;2;R;G;B sets 24-bit RGB foreground; SGR 0 resets",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "1b5b33383b323b3235353b3132383b306d411b5b306d42",
+  "comment": "SGR 38;2;255;128;0 (RGB orange fg) + print A; SGR 0 (reset) + print B; A has RGB fg, B has default",
+  "expected": {
+    "cursor": { "row": 0, "col": 2 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A", "attrs": { "fg_color": { "rgb": [255, 128, 0] } } },
+      { "row": 0, "col": 1, "char": "B" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "wide_char_basic",
+  "description": "CJK character takes 2 columns; subsequent ASCII starts after wide char",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "41e4b8ad42",
+  "comment": "Print A at (0,0); print U+4E2D (中) at (0,1)-(0,2) as 2-col wide char; print B at (0,3); cursor at (0,4)",
+  "expected": {
+    "cursor": { "row": 0, "col": 4 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" },
+      { "row": 0, "col": 1, "char": "中" },
+      { "row": 0, "col": 3, "char": "B" }
+    ]
+  }
+}
